    {
        // Direct Cosmos SQL — references c.Discriminator which is safe because
        // ProductContext preserves the old discriminator property name via
        // HasDiscriminator<string>("Discriminator").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Converted from sync ToList() to async — sync throws in EF Core 9 Cosmos.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

